import socket
import threading

class GameServer:
    def __init__(self):
        self.players = []
        self.game_state = {}
        self.server_socket = None

    def start(self, host='0.0.0.0', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((host, port))

        thread = threading.Thread(target=self.listen_for_status_queries)
        thread.daemon = True
        thread.start()

    def listen_for_status_queries(self):
        while True:
            data, address = self.server_socket.recvfrom(1024)
            if data.decode('utf-8') == 'status':
                response = {
                    'players': self.players,
                    'game_state': self.game_state
                }
                response_str = str(response).encode('utf-8')
                self.server_socket.sendto(response_str, address)

    def add_player(self, player):
        self.players.append(player)
        self.game_state[player] = {'score': 0}

    def remove_player(self, player):
        if player in self.players:
            self.players.remove(player)
            del self.game_state[player]

if __name__ == '__main__':
    game_server = GameServer()
    game_server.start()

    # Example usage
